test_cases.python_test_script:
def test_tc_tcm_shift_001(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert decode_shift_flag(msg) == 1

def test_tc_tcm_shift_002(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert decode_shift_flag(msg) == 0

def test_tc_tcm_shift_003(can_bus):
    flags = [decode_shift_flag(can_bus.recv()) for _ in range(20)]
    assert 1 in flags and 0 in flags

def test_tc_tcm_shift_004(can_bus):
    for _ in range(10):
        assert decode_shift_flag(can_bus.recv()) == 0

def test_tc_tcm_shift_005(can_bus):
    msgs = [decode_shift_flag(can_bus.recv()) for _ in range(5)]
    assert all(f == 1 for f in msgs)

def test_tc_tcm_shift_006(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert decode_shift_flag(msg) == 0
